B.XM=s(["Ol\xe1! Sou a IVE, sua consultora executiva. Posso analisar seu portf\xf3lio agora.","Quer saber qual projeto tem mais potencial de escala neste momento?","Identifico padr\xf5es entre seus projetos. Alguma d\xfavida estrat\xe9gica?"],t.s)
B.XL=s(["Identifiquei oportunidades com alto ROI nesta lista. Posso priorizar para voc\xea.","Cada oportunidade aqui tem crit\xe9rios mensur\xe1veis. Posso explicar qualquer uma.","Quer que eu indique quais oportunidades executar primeiro esta semana?"],t.s)
B.a_e=s(["Este \xe9 seu centro de decis\xe3o. Posso explicar qualquer score em linguagem simples.","Vejo projetos com potencial n\xe3o explorado. Quer uma an\xe1lise detalhada?","Posso simular o impacto de aprovar oportunidades ou concluir a\xe7\xf5es."],t.s)
B.ZV=s(["Seu briefing executivo est\xe1 pronto. Posso destacar o que \xe9 mais urgente.","Quer que eu traduza este relat\xf3rio em pr\xf3ximos passos concretos?","Posso identificar o que mudou esta semana e por qu\xea."],t.s)
B.a_B=s(["Suas personas s\xe3o sua presen\xe7a no mercado. Posso comparar o desempenho de cada uma.","Quer saber qual persona tem maior potencial de crescimento agora?","Posso recomendar estrat\xe9gias espec\xedficas para cada nicho."],t.s)
B.a_A=s(["Seu cofre de conhecimento alimenta toda a intelig\xeancia do sistema.","Qual documento quer que eu analise ou conecte com seus projetos?","Posso mostrar quais conhecimentos est\xe3o gerando mais insights."],t.s)
B.a_z=s(["Sua fila de a\xe7\xf5es determina sua velocidade de execu\xe7\xe3o.","Posso ajudar a priorizar: quais a\xe7\xf5es t\xeam maior impacto no score?","Quer que eu identifique o que est\xe1 bloqueando seu progresso?"],t.s)
B.Zp=s(["Centro de observabilidade completo. Posso auditar qualquer c\xe1lculo.","Quer entender como um score foi gerado? Basta perguntar.","Posso rastrear a origem de qualquer dado ou recomenda\xe7\xe3o."],t.s)
B.a2n=new A.bi(B.Do,[B.XM,B.XL,B.a_e,B.ZV,B.a_B,B.a_A,B.a_z,B.Zp],t.VJ)
